import java.util.Scanner;
import java.nio.ByteBuffer;
import java.nio.charset.StandardCharsets;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        byte[] inputBytes = input.getBytes(StandardCharsets.UTF_8);

        ByteBuffer buffer = ByteBuffer.allocate(10);
        if (inputBytes.length <= buffer.capacity()) {
            buffer.put(inputBytes);
            buffer.flip();
            byte[] outputBytes = new byte[buffer.remaining()];
            buffer.get(outputBytes);

            System.out.println("Buffer contents: " + new String(outputBytes, StandardCharsets.UTF_8));
        } else {
            System.out.println("Input string exceeds buffer size.");
        }
    }
}

